<template><app-content class="h-panel payroll-page"><div class="h-panel-bar"><span class="h-panel-title">工资生成凭证</span></div><div class="h-panel-body"><Table :datas="datas" :border="true"><TableItem title="工资表" prop="sheetName"></TableItem><TableItem title="期间" prop="sheetNo"></TableItem><TableItem title="实发" prop="netAmount"></TableItem><TableItem title="状态" prop="status"></TableItem><TableItem title="凭证ID" prop="voucherId"></TableItem><TableItem title="操作" :width="140" align="center"><div class="actions" slot-scope="{data}"><span v-if="data.status==='AUDITED'&&!data.voucherId" @click="generate(data)">生成凭证</span></div></TableItem></Table></div></app-content></template>
<script>import payroll from '../../api/payroll'; export default { name: 'PayrollVoucher', data() { return {datas: []} }, methods: { loadList() { payroll.sheet.list().then(({data}) => this.datas = data || []) }, generate(row) { payroll.sheet.generateVoucher(row.id).then(() => this.loadList()) } }, mounted() { this.loadList() } }</script>
<style scoped>.actions span{margin:0 5px;color:#3788ee;cursor:pointer}</style>
